1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	type Step = { op: "quote"; items: Item[] };
8	type Customer = { yearsWithMHPCO: number };
9	type Scenario = { customer: Customer; steps: Step[] };
10	type QuoteResult = { premium: number };
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const CURSE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const COMPONENT_BASE_PREMIUM = 25;
18	const BLOCK_SIZE = 3;
19	const BLOCK_BASE_PREMIUM = 60;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	};
27	
28	const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;
29	
30	const componentGroupBase = (count: number): number =>
31	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;
32	
33	const countByType = (items: Item[]): Map<string, number> =>
34	  items.reduce(
35	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
36	    new Map<string, number>(),
37	  );
38	
39	// Returns base premium attributed to a single main item (not components).
40	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
41	
42	// Components are priced per group with block discount.
43	const componentsBaseTotal = (components: Item[]): number =>
44	  [...countByType(components).values()].reduce(
45	    (sum, count) => sum + componentGroupBase(count),
46	    0,
47	  );
48	
49	// Base premium of the whole policy (raw, no item modifiers).
50	const policyBase = (items: Item[]): number => {
51	  const mainBase = items.filter((i) => !isComponent(i)).reduce((sum, i) => sum + itemBasePremium(i), 0);
52	  const compBase = componentsBaseTotal(items.filter(isComponent));
53	  return mainBase + compBase;
54	};
55	
56	// Surcharges that apply to a single item's base premium (cursed, high enchantment).
57	const itemSurcharge = (item: Item): number => {
58	  if (isComponent(item)) return 0;
59	  const base = itemBasePremium(item);
60	  const curseSurcharge = item.cursed ? base * CURSE_RATE : 0;
61	  const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
62	  return curseSurcharge + enchantmentSurcharge;
63	};
64	
65	const itemSurchargesTotal = (items: Item[]): number =>
66	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
67	
68	const quoteStep = (step: Step): QuoteResult => {
69	  const base = policyBase(step.items);
70	  const itemSurcharges = itemSurchargesTotal(step.items);
71	  const firstInsurance = base * FIRST_INSURANCE_RATE;
72	  const premium = Math.ceil(base + itemSurcharges + firstInsurance) + PROCESSING_FEE;
73	  return { premium };
74	};
75	
76	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
77	  const results = scenario.steps.map(quoteStep);
78	  return { results };
79	};
